#include <stdio.h>
#include <stdlib.h>

typedef struct Node {
   int val;
   int numNeighbors;
   struct Node** neighbors;
} Node;

Node* cloneGraph(Node* node) {
   if (!node) return NULL;

   Node* clone = (Node*)malloc(sizeof(Node));
   clone->val = node->val;
   clone->numNeighbors = node->numNeighbors;
   clone->neighbors = (Node**)malloc(sizeof(Node*) * node->numNeighbors);

   for (int i = 0; i < node->numNeighbors; i++) {
      clone->neighbors[i] = cloneGraph(node->neighbors[i]);
   }

   return clone;
}

code.C++:
#include <iostream>
#include <vector>

class Node {
public:
   int val;
   std::vector<Node*> neighbors;

   Node() {
      val = 0;
      neighbors = std::vector<Node*>(0);
   }

   Node(int _val, std::vector<Node*> _neighbors) {
      val = _val;
      neighbors = _neighbors;
   }

   Node* cloneGraph(Node* node) {
      if (!node) return NULL;

      Node* clone = new Node();
      clone->val = node->val;

      for (Node* neighbor : node->neighbors) {
         clone->neighbors.push_back(cloneGraph(neighbor));
      }

      return clone;
   }
};

